        [Fact]
        public void Flatness_QuantityInfo_ReturnsQuantityInfoDescribingQuantity()
        {
            FlatnessUnit[] unitsOrderedByName = EnumHelper.GetValues<FlatnessUnit>().OrderBy(x => x.ToString(), StringComparer.OrdinalIgnoreCase).ToArray();
            var quantity = new Flatness(1, FlatnessUnit.IUnit);

            QuantityInfo<Flatness, FlatnessUnit> quantityInfo = quantity.QuantityInfo;

            Assert.Equal("Flatness", quantityInfo.Name);
            Assert.Equal(Flatness.Zero, quantityInfo.Zero);
            Assert.Equal(Flatness.BaseUnit, quantityInfo.BaseUnitInfo.Value);
            Assert.Equal(unitsOrderedByName, quantityInfo.Units);
            Assert.Equal(unitsOrderedByName, quantityInfo.UnitInfos.Select(x => x.Value));
            Assert.Equal(Flatness.Info, quantityInfo);
            Assert.Equal(quantityInfo, ((IQuantity)quantity).QuantityInfo);
            Assert.Equal(quantityInfo, ((IQuantity<FlatnessUnit>)quantity).QuantityInfo);
        }

