        [Fact]
        public void ConversionRoundTrip()
        {
            Flatness iunit = Flatness.FromIUnits(1);
            AssertEx.EqualTolerance(1, Flatness.FromIUnits(iunit.IUnits).IUnits, IUnitsTolerance);
            AssertEx.EqualTolerance(1, Flatness.FromMicrometersPerMeter(iunit.MicrometersPerMeter).IUnits, MicrometersPerMeterTolerance);
        }

        [Fact]
        public void ArithmeticOperators()
        {
            Flatness v = Flatness.FromIUnits(1);
            AssertEx.EqualTolerance(-1, -v.IUnits, IUnitsTolerance);
            AssertEx.EqualTolerance(2, (Flatness.FromIUnits(3)-v).IUnits, IUnitsTolerance);
            AssertEx.EqualTolerance(2, (v + v).IUnits, IUnitsTolerance);
            AssertEx.EqualTolerance(10, (v*10).IUnits, IUnitsTolerance);
            AssertEx.EqualTolerance(10, (10*v).IUnits, IUnitsTolerance);
            AssertEx.EqualTolerance(2, (Flatness.FromIUnits(10)/5).IUnits, IUnitsTolerance);
            AssertEx.EqualTolerance(2, Flatness.FromIUnits(10)/Flatness.FromIUnits(5), IUnitsTolerance);
        }

        [Fact]
        public void ComparisonOperators()
        {
            Flatness oneIUnit = Flatness.FromIUnits(1);
            Flatness twoIUnits = Flatness.FromIUnits(2);

            Assert.True(oneIUnit < twoIUnits);
            Assert.True(oneIUnit <= twoIUnits);
            Assert.True(twoIUnits > oneIUnit);
            Assert.True(twoIUnits >= oneIUnit);

            Assert.False(oneIUnit > twoIUnits);
            Assert.False(oneIUnit >= twoIUnits);
            Assert.False(twoIUnits < oneIUnit);
            Assert.False(twoIUnits <= oneIUnit);
        }

