        [Theory]
        [InlineData(1, FlatnessUnit.IUnit, 1, FlatnessUnit.IUnit, true)]  // Same value and unit.
        [InlineData(1, FlatnessUnit.IUnit, 2, FlatnessUnit.IUnit, false)] // Different value.
        [InlineData(2, FlatnessUnit.IUnit, 1, FlatnessUnit.MicrometerPerMeter, false)] // Different value and unit.
        [InlineData(1, FlatnessUnit.IUnit, 1, FlatnessUnit.MicrometerPerMeter, false)] // Different unit.
        public void Equals_ReturnsTrue_IfValueAndUnitAreEqual(double valueA, FlatnessUnit unitA, double valueB, FlatnessUnit unitB, bool expectEqual)
        {
            var a = new Flatness(valueA, unitA);
            var b = new Flatness(valueB, unitB);

            // Operator overloads.
            Assert.Equal(expectEqual, a == b);
            Assert.Equal(expectEqual, b == a);
            Assert.Equal(!expectEqual, a != b);
            Assert.Equal(!expectEqual, b != a);

            // IEquatable<T>
            Assert.Equal(expectEqual, a.Equals(b));
            Assert.Equal(expectEqual, b.Equals(a));

            // IEquatable
            Assert.Equal(expectEqual, a.Equals((object)b));
            Assert.Equal(expectEqual, b.Equals((object)a));
        }

        [Fact]
        public void Equals_Null_ReturnsFalse()
        {
            var a = Flatness.Zero;

            Assert.False(a.Equals((object)null));

            // "The result of the expression is always 'false'..."
